    __slots__=("_data","_hash")
    def __init__(self,data=None):
        self._data=dict(data) if data is not None else {}
        self._hash=None
    def __getitem__(self,k): return self._data[k]
    def __iter__(self): return iter(self._data)
    def __len__(self): return len(self._data)
    def __hash__(self):
        if self._hash is None: self._hash=hash(frozenset(self._data.items()))
        return self._hash
    def __eq__(self,o):
        if isinstance(o,Mapping): return dict(self._data)==dict(o)
        return NotImplemented

# Case A: FLAT nested mutable that IS the same shape -> equal but one unhashable
# directly-constructed from mutable vs another directly-constructed identical
a = FrozenDictMain({"k":[1,2]})   # value is list -> _data has list
b = FrozenDictMain({"k":[1,2]})
print("flat: a==b?", a==b)
try: hash(a); print("flat: a hashable")
except TypeError: print("flat: a NOT hashable (list inside)")

# Equal-vs-equal-hash with one frozen-equivalent: compare directly-constructed (shallow) to a properly frozen one
# Use a value that dict==dict treats equal across dict and FrozenDict nested:
# main freeze of {"k":{"x":1}} -> nested FrozenDict; direct construct -> nested dict.
# dict({"k": FrozenDict({"x":1})}) == dict({"k": {"x":1}}) ?  FrozenDict.__eq__ to dict is True.
class FDcur(FrozenDictMain):  # current-style deep
    def __init__(self,data=None):
        super().__init__()
        self._data = {k:(FDcur(v) if isinstance(v,Mapping) else v) for k,v in (data or {}).items()}
        self._hash=None
direct = FrozenDictMain({"k":{"x":1}})   # shallow: nested plain dict
frozen = FDcur({"k":{"x":1}})            # deep: nested FrozenDict
